import { createLinterRuleTester, LinterRuleTester } from "@typespec/compiler/testing";
import { beforeEach, describe, it } from "vitest";
import { Tester } from "../testing/test-host.js";
import { projectsTargetsInvariantRule } from "./projects-targets-invariant.rule.js";

const ENTITY = `
  namespace Products.MyProduct.Entities.Task {
    @entity
    model Task { id: string; }
  }
  using Products.MyProduct.Entities.Task;
`;

const FEATURE_WITH_INV = `
  @feature
  namespace Products.MyProduct.Features.Lifecycle {
    @invariant(#{ predicate: "A {@Task} has an id.", why: "Reason." })
    op task_has_id(): void;
  }
`;

// Note: "invalid" cases for this rule (wrongTarget, wrongSource) trigger @projects decorator
// errors at type-checker level (projects-op-must-target-invariant, projects-op-not-proof),
// which prevent the linter phase from running. The decorator already enforces these constraints.
// Tests below cover valid scenarios to ensure the rule doesn't over-fire.

describe("projects-targets-invariant rule", () => {
  let ruleTester: LinterRuleTester;

  beforeEach(async () => {
    const runner = await Tester.createInstance();
    ruleTester = createLinterRuleTester(runner, projectsTargetsInvariantRule, "@a10n/blueprint-typespec");
  });

  // ─── valid ────────────────────────────────────────────────────────────────

  describe("valid", () => {
    // a10n:blueprint Components.A10nBlueprintTypespecSdk.Tests.Rules.T023.T023_01
    // a10n:blueprint:test Components.A10nBlueprintTypespecSdk.Operations.rule_projects_targets_invariant:Products.A10nBlueprintEngine.Features.SystemAuthoring.op_projects_inv:must
    // a10n:blueprint:test-steps Components.A10nBlueprintTypespecSdk.Operations.rule_projects_targets_invariant
    it("projecting-op-kind op (@tool in Agent) targeting an @invariant passes", async () => {
      await ruleTester
        .expect(`
          ${ENTITY}
          ${FEATURE_WITH_INV}
          @component(#{ type: ComponentType.Agent })
          namespace Components.MyAgent {
            @tool(#{ sequential: false })
            @projects(Products.MyProduct.Features.Lifecycle.task_has_id)
            op do_task(): void;
          }
        `)
        .toBeValid();
    });

    // a10n:blueprint Components.A10nBlueprintTypespecSdk.Tests.Rules.T023.T023_02
    it("op without @projects is not flagged", async () => {
      await ruleTester
        .expect(`
          ${ENTITY}
          ${FEATURE_WITH_INV}
          @component(#{ type: ComponentType.Agent })
          namespace Components.MyAgent {
            @tool(#{ sequential: false })
            op do_task(): void;
          }
        `)
        .toBeValid();
    });

    // a10n:blueprint Components.A10nBlueprintTypespecSdk.Tests.Rules.T023.T023_03
    it("@signal targeting an @invariant passes (signal is projecting-op-kind)", async () => {
      await ruleTester
        .expect(`
          ${ENTITY}
          ${FEATURE_WITH_INV}
          @component(#{ type: ComponentType.Agent })
          namespace Components.MyAgent {
            @eval(#{ title: "e" })
            namespace Evals.Lifecycle.E001 {
              @signal(#{
                title: "s",
                method: SignalMethod.Deterministic,
                criteria: "criteria",
                examples: #[],
              })
              @projects(Products.MyProduct.Features.Lifecycle.task_has_id)
              op E001_01(): boolean;
            }
          }
        `)
        .toBeValid();
    });
  });
});
